"use client";

import { FormEvent, useEffect, useState } from "react";

type RightObject = {
  id: string;
  title: string;
  kind: string;
  description: string;
  ownerName?: string;
  ownerEmail?: string;
  contentHash: string;
  createdAt: string;
};

const API_BASE =
  process.env.NEXT_PUBLIC_API_BASE_URL || "http://localhost:4001";

export default function QRightPage() {
  const [objects, setObjects] = useState<RightObject[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [saving, setSaving] = useState(false);
  const [formError, setFormError] = useState<string | null>(null);

  // Поля формы
  const [title, setTitle] = useState("");
  const [kind, setKind] = useState("idea");
  const [description, setDescription] = useState("");
  const [ownerName, setOwnerName] = useState("");
  const [ownerEmail, setOwnerEmail] = useState("");
  const [rawContent, setRawContent] = useState("");

  const loadObjects = async () => {
    try {
      setLoading(true);
      const res = await fetch(`${API_BASE}/api/qright/objects`);
      if (!res.ok) throw new Error("Не удалось загрузить объекты");

      const data = await res.json();
      setObjects(data.items || []);
      setError(null);
    } catch (e) {
      setError((e as Error).message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    loadObjects();
  }, []);

  const handleSubmit = async (e: FormEvent) => {
    e.preventDefault();
    setFormError(null);

    if (!title.trim() || !description.trim()) {
      setFormError("Название и описание обязательны");
      return;
    }

    try {
      setSaving(true);
      const res = await fetch(`${API_BASE}/api/qright/objects`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          title,
          kind,
          description,
          ownerName: ownerName || undefined,
          ownerEmail: ownerEmail || undefined,
          rawContent: rawContent || undefined,
        }),
      });

      if (!res.ok) {
        const data = await res.json().catch(() => null);
        throw new Error(data?.error || "Ошибка при регистрации объекта");
      }

      // очистить форму
      setTitle("");
      setDescription("");
      setOwnerName("");
      setOwnerEmail("");
      setRawContent("");
      setKind("idea");

      // обновить список
      await loadObjects();
    } catch (e) {
      setFormError((e as Error).message);
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-50">
      <header className="border-b border-slate-800 px-6 py-4">
        <h1 className="text-xl font-bold">QRight · Электронное патентирование</h1>
        <p className="text-sm text-slate-400 mt-1">
          Регистрация идей и объектов интеллектуальной собственности в экосистеме AEVION.
        </p>
      </header>

      <div className="px-6 py-6 grid gap-8 lg:grid-cols-[minmax(0,2fr)_minmax(0,3fr)]">
        {/* Форма */}
        <section>
          <h2 className="text-lg font-semibold mb-3">Новый объект ИС</h2>

          <form onSubmit={handleSubmit} className="space-y-3">
            <div>
              <label className="block text-sm mb-1">Название *</label>
              <input
                value={title}
                onChange={(e) => setTitle(e.target.value)}
                className="w-full rounded-md border border-slate-700 bg-slate-900 px-3 py-2 text-sm outline-none focus:border-sky-500"
              />
            </div>

            <div>
              <label className="block text-sm mb-1">Тип</label>
              <select
                value={kind}
                onChange={(e) => setKind(e.target.value)}
                className="w-full rounded-md border border-slate-700 bg-slate-900 px-3 py-2 text-sm outline-none focus:border-sky-500"
              >
                <option value="idea">Идея / концепция</option>
                <option value="code">Код</option>
                <option value="design">Дизайн</option>
                <option value="music">Музыка / аудио</option>
                <option value="text">Текст / статья</option>
                <option value="other">Другое</option>
              </select>
            </div>

            <div>
              <label className="block text-sm mb-1">Описание *</label>
              <textarea
                value={description}
                onChange={(e) => setDescription(e.target.value)}
                rows={4}
                className="w-full rounded-md border border-slate-700 bg-slate-900 px-3 py-2 text-sm outline-none focus:border-sky-500"
              />
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
              <div>
                <label className="block text-sm mb-1">Имя автора</label>
                <input
                  value={ownerName}
                  onChange={(e) => setOwnerName(e.target.value)}
                  className="w-full rounded-md border border-slate-700 bg-slate-900 px-3 py-2 text-sm outline-none focus:border-sky-500"
                />
              </div>
              <div>
                <label className="block text-sm mb-1">Email автора</label>
                <input
                  value={ownerEmail}
                  onChange={(e) => setOwnerEmail(e.target.value)}
                  className="w-full rounded-md border border-slate-700 bg-slate-900 px-3 py-2 text-sm outline-none focus:border-sky-500"
                />
              </div>
            </div>

            <div>
              <label className="block text-sm mb-1">
                Исходное содержимое (необязательно, для хэша)
              </label>
              <textarea
                value={rawContent}
                onChange={(e) => setRawContent(e.target.value)}
                rows={3}
                className="w-full rounded-md border border-slate-700 bg-slate-900 px-3 py-2 text-sm outline-none focus:border-sky-500"
              />
              <p className="text-xs text-slate-500 mt-1">
                Если заполнить, хэш будет считаться именно от этого содержания.
              </p>
            </div>

            {formError && (
              <div className="text-sm text-red-400">{formError}</div>
            )}

            <button
              type="submit"
              disabled={saving}
              className="rounded-md bg-sky-600 px-4 py-2 text-sm font-medium hover:bg-sky-500 disabled:opacity-60"
            >
              {saving ? "Регистрация..." : "Зарегистрировать объект"}
            </button>
          </form>
        </section>

        {/* Список объектов */}
        <section>
          <h2 className="text-lg font-semibold mb-3">
            Зарегистрированные объекты
          </h2>

          {loading ? (
            <div className="text-sm text-slate-400">Загрузка...</div>
          ) : error ? (
            <div className="text-sm text-red-400">Ошибка: {error}</div>
          ) : objects.length === 0 ? (
            <div className="text-sm text-slate-400">
              Пока нет зарегистрированных объектов.
            </div>
          ) : (
            <div className="space-y-3 max-h-[70vh] overflow-auto pr-2">
              {objects.map((o) => (
                <article
                  key={o.id}
                  className="rounded-md border border-slate-800 bg-slate-900/70 p-3 text-sm"
                >
                  <div className="text-xs text-slate-400 mb-1">
                    {o.kind} • {new Date(o.createdAt).toLocaleString()}
                  </div>
                  <h3 className="font-semibold mb-1">{o.title}</h3>
                  <p className="text-slate-200 mb-1">{o.description}</p>
                  {(o.ownerName || o.ownerEmail) && (
                    <div className="text-xs text-slate-400 mb-1">
                      Автор: {o.ownerName || "—"}{" "}
                      {o.ownerEmail && <>({o.ownerEmail})</>}
                    </div>
                  )}
                  <div className="text-[10px] text-slate-500 break-all">
                    Хэш: {o.contentHash}
                  </div>
                </article>
              ))}
            </div>
          )}
        </section>
      </div>
    </div>
  );
}
